/**
 * @fileoverview InfiniteScroll component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/InfiniteScroll.def
 */

import razyui from '../index.js';
import { PART } from './InfiniteScroll/constants.js';

export const InfiniteScrollDef = {
    name: 'InfiniteScroll',
    tag: 'rui-infinite-scroll',

    // -------------------------------------------------------------------------
    //  Design Tokens
    // -------------------------------------------------------------------------
    tokens: {
        prefix: 'is',
        tokens: {
            'padding':        { value: '2rem 1rem',   description: 'Sentinel padding' },
            'min-height':     { value: '64px',         description: 'Sentinel minimum height' },
            'dot-size':       { value: '8px',          description: 'Loading dot size' },
            'end-font-size':  { value: '0.85rem',      description: 'End message font size' },
            'accent':         { ref: 'color.accent',   description: 'Accent color (dots)' },
            'danger':         { ref: 'color.danger',   description: 'Error color' },
            'danger-bg':      { ref: 'color.danger-bg', description: 'Error background' },
            'radius-sm':      { ref: 'radius.sm',      description: 'Small radius' },
            'text-muted':     { ref: 'color.text-muted', description: 'Muted text color' },
        },
    },

    // -------------------------------------------------------------------------
    //  State Machine
    // -------------------------------------------------------------------------
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { LOAD: 'loading' },
            },
            loading: {
                on: { LOADED: 'idle', DONE: 'done', ERROR: 'error' },
            },
            error: {
                on: { RETRY: 'loading' },
            },
            done: {},
        },
        effects: {
            loading(ctx) {
                if (ctx.sentinel) razyui(ctx.sentinel).removeClass('is-idle', 'is-error-state', 'is-done');
                if (ctx.sentinel) razyui(ctx.sentinel).addClass('is-loading');
            },
            idle(ctx) {
                if (ctx.sentinel) razyui(ctx.sentinel).removeClass('is-loading', 'is-error-state', 'is-done');
                if (ctx.sentinel) razyui(ctx.sentinel).addClass('is-idle');
            },
            error(ctx) {
                if (ctx.sentinel) razyui(ctx.sentinel).removeClass('is-loading', 'is-idle', 'is-done');
                if (ctx.sentinel) razyui(ctx.sentinel).addClass('is-error-state');
            },
            done(ctx) {
                if (ctx.sentinel) razyui(ctx.sentinel).removeClass('is-loading', 'is-idle', 'is-error-state');
                if (ctx.sentinel) razyui(ctx.sentinel).addClass('is-done');
            },
        },
    },

    // -------------------------------------------------------------------------
    //  Template Slots
    // -------------------------------------------------------------------------
    template: {
        slots: {
            sentinel: { element: 'div', classes: ['is-sentinel'] },
            dots:     { element: 'div', classes: ['is-dots'] },
            dot:      { element: 'span', classes: ['is-dot'] },
            end:      { element: 'div', classes: ['is-end'] },
            error:    { element: 'div', classes: ['is-error'] },
        },
    },

    // -------------------------------------------------------------------------
    //  Custom Element
    // -------------------------------------------------------------------------
    ce: {
        tag: 'rui-infinite-scroll',
        observedAttrs: ['threshold', 'disabled'],
        attrMap: {
            threshold: 'threshold',
            disabled:  'disabled',
        },
    },

    jitParts: {
        [PART.SENTINEL]: PART.SENTINEL,
        [PART.SPINNER]: PART.SPINNER,
        [PART.DOT]: PART.DOT,
        [PART.END]: PART.END,
        [PART.ERROR]: PART.ERROR,
    },

    styles: {},
};

export default InfiniteScrollDef;
