/**
 * @fileoverview InfiniteScroll barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/InfiniteScroll
 */
import { default as razyui } from '../index.js';
import { InfiniteScrollDef as DEF } from './InfiniteScroll.def.js';
import InfiniteScroll from './InfiniteScroll/index.js';

// ── Module registration ──
razyui.InfiniteScroll = InfiniteScroll;

// ── JIT Component Definition registration ──
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// ── Custom Element registration ──
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, InfiniteScroll);
}

export default InfiniteScroll;
export const stylesheet = null;
