/**
 * @fileoverview InfiniteScroll constants — CSS classes, selectors, default config, sentinel markup.
 * @module module/InfiniteScroll/constants
 */
import { defineParts } from '../shared/definePart.js';


/** CSS class names applied to the sentinel element */
export const CLS = Object.freeze({
    SENTINEL:    'is-sentinel',
    SPINNER:     'is-spinner',
    DOT:         'is-dot',
    END:         'is-end',
    ERROR:       'is-error',
    LOADING:     'is-loading',
    DONE:        'is-done',
    ERROR_STATE: 'is-error-state',
    IDLE:        'is-idle',
});

/** Default spinner HTML (3-dot bounce) */
export const DEFAULT_SPINNER_HTML =
    '<span class="is-dot"></span>' +
    '<span class="is-dot"></span>' +
    '<span class="is-dot"></span>';

/** razyui.spell() expression for sentinel structure */
export const SENTINEL_SPELL = 'div.is-sentinel[data-slot=sentinel](div.is-end[data-slot=end],div.is-error[data-slot=error])';
export const SPINNER_SPELL  = 'div.is-spinner[data-slot=spinner]';

/** Scroll overflow test pattern */
export const OVERFLOW_RE = /(auto|scroll)/;

/** Default configuration */
export const DEFAULTS = Object.freeze({
    threshold:    200,
    initialLoad:  true,
    spinner:      true,
    spinnerHTML:  '',
    endMessage:   'No more data',
    errorMessage: 'Load failed — tap to retry',
    debounce:     100,
    onLoad:       null,
    onError:      null,
    onEnd:        null,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('InfiniteScroll', {
    SENTINEL    : { class: 'is-sentinel', aliases: ['sentinel', 'root', 'container'] },
    SPINNER     : { class: 'is-spinner', aliases: ['spinner'] },
    DOT         : { class: 'is-dot' },
    END         : { class: 'is-end' },
    ERROR       : { class: 'is-error' },
});

PART.SENTINEL.jit = 'flex items-center justify-center [padding:2rem_1rem] [min-height:64px] {is-idle}:[min-height:1px] {is-idle}:[padding:0] [&>*]:hidden {is-loading}:[&>.is-spinner]:flex {is-done}:[&>.is-end]:block {is-error-state}:[&>.is-error]:block';
PART.SPINNER.jit  = 'flex items-center justify-center gap-[6px]';
PART.DOT.jit      = 'w-[8px] h-[8px] rounded-[50%] bg-[var(--is-accent)] motion-bounce nth-2:[animation-delay:.15s] nth-3:[animation-delay:.3s]';
PART.END.jit      = 'text-center fg-[var(--is-text-muted)] text-[.85rem] [letter-spacing:.02em] [padding:.5rem_0]';
PART.ERROR.jit    = 'text-center fg-[var(--is-danger)] text-[.85rem] cursor-pointer [padding:.5rem_1rem] rounded-[var(--is-radius-sm)] hover:bg-[var(--is-danger-bg)]';