/**
 * @fileoverview InfiniteScroll events — IntersectionObserver / scroll binding with AbortController.
 * @module module/InfiniteScroll/events
 */

import razyui from '../../index.js';

/**
 * Bind an IntersectionObserver on the sentinel element.
 * Falls back to a debounced scroll listener when IO is unavailable.
 *
 * Returns a cleanup function that disconnects the observer and/or
 * removes the scroll listener.
 *
 * @param {object} opts
 * @param {HTMLElement}      opts.sentinel     — element to observe
 * @param {HTMLElement|null} opts.container    — scrollable container (null = window)
 * @param {EventTarget}     opts.scrollTarget — element that receives scroll events
 * @param {number}          opts.threshold    — px from bottom to trigger
 * @param {number}          opts.debounce     — ms debounce for scroll fallback
 * @param {Function}        opts.onNearBottom — callback when sentinel enters view / scroll near bottom
 * @param {Function}        opts.checkScroll  — manual scroll-distance check (fallback path)
 * @returns {{ observer: IntersectionObserver|null, scrollHandler: Function|null, cleanup: Function }}
 */
export function bindScrollEvents(opts) {
    const {
        sentinel, container, scrollTarget,
        threshold, debounce, onNearBottom, checkScroll,
    } = opts;

    let observer      = null;
    let scrollHandler = null;

    if ('IntersectionObserver' in window) {
        observer = new IntersectionObserver(entries => {
            for (const e of entries) {
                if (e.isIntersecting) onNearBottom();
            }
        }, {
            root: container || null,
            rootMargin: `0px 0px ${threshold}px 0px`,
        });
        observer.observe(sentinel);
    } else {
        // Fallback: debounced scroll listener
        let timer = null;
        scrollHandler = () => {
            if (timer) return;
            timer = setTimeout(() => {
                timer = null;
                checkScroll();
            }, debounce);
        };
        razyui(scrollTarget).on('scroll', scrollHandler, { passive: true });
    }

    /** Cleanup — disconnect observer and/or remove scroll listener */
    function cleanup() {
        if (observer) {
            observer.disconnect();
            observer = null;
        }
        if (scrollHandler) {
            razyui(scrollTarget).off('scroll');
            scrollHandler = null;
        }
    }

    return { observer, scrollHandler, cleanup };
}

/**
 * Re-observe the sentinel so the IntersectionObserver fires again
 * if the sentinel is still in view after a load cycle.
 *
 * @param {IntersectionObserver|null} observer
 * @param {HTMLElement|null} sentinel
 */
/**
 * Bind retry-click on the sentinel's error element.
 *
 * @param {HTMLElement} sentinel — sentinel root
 * @param {Function} retryFn — callback on click
 */
export function bindRetryClick(sentinel, retryFn) {
    const err = razyui(sentinel).find('.is-error');
    if (err.length) err.on('click', retryFn);
}

export function reobserve(observer, sentinel) {
    if (!observer || !sentinel) return;
    observer.unobserve(sentinel);
    observer.observe(sentinel);
}
