/**
 * @fileoverview InfiniteScroll component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, default config, sentinel markup
 *   state.js     — reactive state wiring
 *   view.js      — sentinel DOM build / teardown + state display
 *   events.js    — IntersectionObserver / scroll binding with cleanup
 *
 * @module module/InfiniteScroll
 */

import { default as razyui } from '../../index.js';

import { DEFAULTS, OVERFLOW_RE }                                  from './constants.js';
import { createReactiveState, syncState }                         from './state.js';
import { buildSentinel, insertSentinel, updateSentinelState,
         keepSentinelLast, removeSentinel }                       from './view.js';
import { bindScrollEvents, reobserve, bindRetryClick }            from './events.js';
import { emitEvent }                                              from '../shared/emitEvent.js';

/**
 * InfiniteScroll — v2 modular rewrite (JIT-compatible)
 *
 * Lazy-loading / infinite scroll that fires a callback when the user
 * scrolls near the bottom of a container (or the window).  Perfect for
 * paginated lists, feeds, image galleries, and any "load more" pattern.
 *
 * Features:
 *   - Works on any scrollable element **or** the window/document
 *   - Configurable threshold (px or % from bottom)
 *   - Built-in spinner / "loading" indicator (auto show/hide)
 *   - "No more data" end-state with custom message
 *   - Manual retry on error
 *   - Debounced scroll listener for performance
 *   - Page counter auto-increments
 *   - getControl() API: load(), reset(), done(), destroy()
 *   - Reactive state (loading, page, hasMore)
 *
 * Config:
 *   onLoad(page)      — **required** async callback, return data or throw
 *   threshold         — px from bottom to trigger (default 200)
 *   initialLoad       — auto-fire page 1 on construction (default true)
 *   spinner           — show built-in spinner (default true)
 *   spinnerHTML       — custom spinner markup
 *   endMessage        — text shown when no more data (default 'No more data')
 *   errorMessage      — text shown on error (default 'Load failed — tap to retry')
 *   debounce          — ms scroll debounce (default 100)
 *
 * Callbacks:
 *   onLoad(page)          — must return a promise. Resolve = success, reject = error.
 *                            Return `false` or resolve(false) to signal "no more data".
 *   onError(error, page)  — optional error handler
 *   onEnd()               — fires when hasMore becomes false
 */
const InfiniteScroll = class {

    // ── Private fields ──────────────────────────

    #container    = null;   // the scrollable element (or null = window)
    #contentEl    = null;   // the element content is appended to
    #sentinel     = null;   // the bottom sentinel element we observe / measure
    #config       = {};
    #stateRef     = null;
    #setState     = null;
    #destroyed    = false;

    #page         = 0;
    #loading      = false;
    #hasMore      = true;
    #error        = false;

    #scrollTarget = null;   // element that receives the scroll listener
    #observer     = null;   // IntersectionObserver (preferred path)
    #scrollCleanup = null;  // cleanup function from bindScrollEvents

    /** Emit a prefixed rui-* event from the content element. */
    #emit(name, detail = {}) {
        const el = this.#contentEl?.[0] ?? this.#contentEl;
        if (el) emitEvent(el, name, detail);
    }

    // ────────────────────────────────────────────
    // Constructor
    // ────────────────────────────────────────────

    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve JIT spacing token for threshold
        this.#config.threshold = razyui.JIT.TOKEN.spacePx(this.#config.threshold);

        if (typeof this.#config.onLoad !== 'function') {
            console.warn('InfiniteScroll: onLoad callback is required');
            return;
        }

        // Resolve container
        const el = razyui.isStr(selector)
            ? razyui(selector)[0]
            : selector;
        if (!el) { console.warn('InfiniteScroll: element not found →', selector); return; }

        // Always keep a reference to the content element for sentinel placement
        this.#contentEl = el;

        if (el && el !== document && el !== document.documentElement && el !== document.body) {
            // Check if the element itself is scrollable (has overflow scroll/auto)
            const style = getComputedStyle(el);
            const isScrollable = OVERFLOW_RE.test(style.overflow + style.overflowY);

            if (isScrollable) {
                // Container mode — sentinel lives inside the scrollable element
                this.#container = el;
                this.#scrollTarget = el;
            } else {
                // Window mode — element is just a content wrapper
                this.#container = null;
                this.#scrollTarget = window;
            }
        } else {
            // Window mode
            this.#container = null;
            this.#scrollTarget = window;
        }

        this.#buildSentinel();
        this.#setupState();
        this.#bindScroll();

        if (this.#config.initialLoad) {
            // Small delay so caller can chain getControl() first
            requestAnimationFrame(() => { if (!this.#destroyed) this.#loadNext(); });
        }
    }

    // ────────────────────────────────────────────
    // Sentinel DOM
    // ────────────────────────────────────────────

    #buildSentinel() {
        this.#sentinel = buildSentinel(
            razyui.spell.bind(razyui),
            this.#config,
        );
        bindRetryClick(this.#sentinel, () => this.#retry());
        insertSentinel(this.#sentinel, this.#container, this.#contentEl);
        this.#updateSentinelState();
    }

    #updateSentinelState() {
        updateSentinelState(this.#sentinel, this.#loading, this.#hasMore, this.#error);
    }

    #keepSentinelLast() {
        keepSentinelLast(this.#sentinel);
    }

    #reobserve() {
        if (this.#destroyed) return;
        reobserve(this.#observer, this.#sentinel);
    }

    // ────────────────────────────────────────────
    // Reactive state
    // ────────────────────────────────────────────

    #setupState() {
        const { ref, setState } = createReactiveState(razyui.state, {
            page: this.#page,
            loading: false,
            hasMore: true,
        });
        this.#stateRef = ref;
        this.#setState = setState;
    }

    #syncState() {
        syncState(this.#setState, {
            page:    this.#page,
            loading: this.#loading,
            hasMore: this.#hasMore,
        });
        const el = this.#container || (this.#contentEl?.[0] ?? this.#contentEl);
        if (el) el.setAttribute('aria-busy', String(this.#loading));
    }

    // ────────────────────────────────────────────
    // Scroll binding
    // ────────────────────────────────────────────

    #bindScroll() {
        const result = bindScrollEvents({
            sentinel:     this.#sentinel,
            container:    this.#container,
            scrollTarget: this.#scrollTarget,
            threshold:    this.#config.threshold,
            debounce:     this.#config.debounce,
            onNearBottom: () => this.#onNearBottom(),
            checkScroll:  () => this.#checkScroll(),
        });
        this.#observer     = result.observer;
        this.#scrollCleanup = result.cleanup;
    }

    #checkScroll() {
        if (this.#destroyed || this.#loading || !this.#hasMore || this.#error) return;

        let scrollBottom;
        if (this.#container) {
            const { scrollTop, scrollHeight, clientHeight } = this.#container;
            scrollBottom = scrollHeight - scrollTop - clientHeight;
        } else {
            const { scrollTop, scrollHeight, clientHeight } = document.documentElement;
            scrollBottom = scrollHeight - scrollTop - clientHeight;
        }

        if (scrollBottom <= this.#config.threshold) {
            this.#onNearBottom();
        }
    }

    #onNearBottom() {
        if (this.#loading || !this.#hasMore || this.#error || this.#destroyed) return;
        this.#loadNext();
    }

    // ────────────────────────────────────────────
    // Load logic
    // ────────────────────────────────────────────

    async #loadNext() {
        if (this.#loading || !this.#hasMore || this.#destroyed) return;

        this.#loading = true;
        this.#error = false;
        this.#page++;
        this.#keepSentinelLast();   // spinner shows at the bottom
        this.#updateSentinelState();
        this.#syncState();

        try {
            const result = await this.#config.onLoad(this.#page);

            if (this.#destroyed) return;

            // User's callback may have appended content — move sentinel back to the end
            this.#keepSentinelLast();

            // If callback returns false → no more data
            if (result === false) {
                this.#hasMore = false;
                this.#loading = false;
                this.#updateSentinelState();
                this.#syncState();
                if (this.#config.onEnd) this.#config.onEnd();
                this.#emit('done', { page: this.#page });
                return;
            }

            this.#loading = false;
            this.#updateSentinelState();
            this.#syncState();
            this.#emit('load', { page: this.#page });

            // Re-observe so the observer fires again if sentinel is still in view;
            // for the scroll-fallback path, do a manual check after DOM settles.
            if (this.#observer) {
                this.#reobserve();
            } else {
                requestAnimationFrame(() => {
                    if (!this.#destroyed && this.#hasMore && !this.#loading) {
                        this.#checkScroll();
                    }
                });
            }

        } catch (err) {
            if (this.#destroyed) return;
            this.#loading = false;
            this.#error = true;
            this.#page--;  // rollback page so retry re-attempts same page
            this.#keepSentinelLast();
            this.#updateSentinelState();
            this.#syncState();
            if (this.#config.onError) this.#config.onError(err, this.#page + 1);
            this.#emit('error', { error: err, page: this.#page + 1 });
        }
    }

    #retry() {
        if (this.#destroyed || this.#loading) return;
        this.#error = false;
        this.#updateSentinelState();
        this.#loadNext();
    }

    // ────────────────────────────────────────────
    // getControl() API
    // ────────────────────────────────────────────

    getControl() {
        const self = this;
        return {
            /** Current page number */
            get page()    { return self.#page; },
            /** Whether a load is in progress */
            get loading() { return self.#loading; },
            /** Whether there is more data to load */
            get hasMore() { return self.#hasMore; },
            /** The sentinel element */
            get sentinel() { return self.#sentinel; },
            /** The scroll container (null = window) */
            get container() { return self.#container; },
            /** The root element (container or content wrapper) */
            get element() { return self.#container ?? self.#contentEl; },

            /** Manually trigger a load */
            load: () => {
                if (self.#destroyed || self.#loading || !self.#hasMore) return;
                self.#loadNext();
            },

            /** Signal "no more data" from outside */
            done: () => {
                self.#hasMore = false;
                self.#loading = false;
                self.#error = false;
                self.#updateSentinelState();
                self.#syncState();
                if (self.#config.onEnd) self.#config.onEnd();
            },

            /** Reset to page 0 and start fresh */
            reset: () => {
                self.#page = 0;
                self.#loading = false;
                self.#hasMore = true;
                self.#error = false;

                // Re-attach sentinel if it was detached (e.g. parent.innerHTML = '')
                if (self.#sentinel && !self.#sentinel.parentNode) {
                    const parent = self.#container || self.#contentEl;
                    if (parent) razyui(parent).append(self.#sentinel);
                }

                self.#keepSentinelLast();
                self.#updateSentinelState();
                self.#syncState();

                // Re-observe
                self.#reobserve();

                self.#loadNext();
            },

            /** Destroy the instance */
            destroy: () => self.destroy(),
            get destroyed() { return self.#destroyed; },
        };
    }

    // ────────────────────────────────────────────
    // Destroy
    // ────────────────────────────────────────────

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;

        // Disconnect observer and remove scroll listener
        if (this.#scrollCleanup) {
            this.#scrollCleanup();
            this.#scrollCleanup = null;
        }
        this.#observer = null;

        removeSentinel(this.#sentinel);
        this.#sentinel = null;
    }
};

export default InfiniteScroll;
